import java.util.*;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.locks.ReentrantReadWriteLock;
import java.util.function.Consumer;

public class LRUCache<K, V> {

    private final int maxSize;
    private final Map<K, CacheEntry<K, V>> cacheMap;
    private final DoublyLinkedList<K, V> lruList;
    private final ReentrantReadWriteLock lock;
    private final AtomicLong hitCount;
    private final AtomicLong missCount;
    private final AtomicLong evictionCount;
    private final AtomicLong expirationCount;
    private final Consumer<CacheEntry<K, V>> evictionCallback;

    // Cache entry with TTL support
    private static class CacheEntry<K, V> {
        final K key;
        final V value;
        final long createdAt;
        final long ttlMillis;
        final long expiresAt;
        Node<K, V> node;

        CacheEntry(K key, V value, long ttlMillis, long currentTime) {
            this.key = key;
            this.value = value;
            this.createdAt = currentTime;
            this.ttlMillis = ttlMillis;
            this.expiresAt = ttlMillis <= 0 ? Long.MAX_VALUE : currentTime + ttlMillis;
        }

        boolean isExpired(long currentTime) {
            return ttlMillis <= 0 ? false : currentTime >= expiresAt;
        }
    }

    // Doubly linked list for LRU ordering
    private static class DoublyLinkedList<K, V> {
        private Node<K, V> head;
        private Node<K, V> tail;
        private int size;

        private static class Node<K, V> {
            K key;
            V value;
            Node<K, V> prev;
            Node<K, V> next;

            Node(K key, V value) {
                this.key = key;
                this.value = value;
            }
        }

        void addToHead(Node<K, V> node) {
            node.prev = null;
            node.next = head;
            if (head != null) {
                head.prev = node;
            }
            head = node;
            if (tail == null) {
                tail = node;
            }
            size++;
        }

        void removeNode(Node<K, V> node) {
            if (node.prev != null) {
                node.prev.next = node.next;
            } else {
                head = node.next;
            }
            if (node.next != null) {
                node.next.prev = node.prev;
            } else {
                tail = node.prev;
            }
            size--;
        }

        void moveToFront(Node<K, V> node) {
            if (node == head) return;
            removeNode(node);
            addToHead(node);
        }

        Node<K, V> removeTail() {
            if (tail == null) return null;
            Node<K, V> removed = tail;
            removeNode(tail);
            return removed;
        }

        void clear() {
            head = null;
            tail = null;
            size = 0;
        }
    }

    public LRUCache(int maxSize) {
