        return total == 0 ? 0.0 : (double) hitCount.get() / total;
    }

    public void clear() {
        lock.writeLock().lock();
        try {
            for (CacheEntry<K, V> entry : cacheMap.values()) {
                if (evictionCallback != null) {
                    evictionCallback.accept(entry);
                }
            }
            cacheMap.clear();
            lruList.clear();
        } finally {
            lock.writeLock().unlock();
