    }

    public boolean containsKey(K key) {
        long currentTime = System.currentTimeMillis();
        lock.readLock().lock();
        try {
            CacheEntry<K, V> entry = cacheMap.get(key);
            return entry != null && !entry.isExpired(currentTime);
        } finally {
